import type {
    CurrencyCode,
      Project,
        Transaction,
        } from '../models/types';

        import { saveProject } from './database';

        import {
          now,
            uid,
            } from '../utils/format';

            import {
              rateOf,
                toYER,
                } from '../utils/currency';

                type Base = {
                  amount?: number;
                    currency: CurrencyCode;
                      date: string;
                        title?: string;
                          notes?: string;
                            quantity?: number;
                              unit?: string;
                                unitPrice?: number;
                                  relatedId?: string;
                                  };

                                  const makeTx = (
                                    project: Project,
                                      data: Omit<
                                          Transaction,
                                              'id' |
                                                    'projectId' |
                                                          'createdAt' |
                                                                'updatedAt'
                                                                  >
                                                                  ): Transaction => ({
                                                                    ...data,
                                                                      id: uid(),
                                                                        projectId: project.id,
                                                                          createdAt: now(),
                                                                            updatedAt: now(),
                                                                            });

                                                                            const commit = (
                                                                              project: Project,
                                                                                rows: Transaction[]
                                                                                ) => {
                                                                                  const updated: Project = {
                                                                                      ...project,
                                                                                          transactions: [
                                                                                                ...rows,
                                                                                                      ...project.transactions,
                                                                                                          ],
                                                                                                              updatedAt: now(),
                                                                                                                };

                                                                                                                  saveProject(updated);

                                                                                                                    return updated;
                                                                                                                    };

                                                                                                                    const amountYER = (
                                                                                                                      project: Project,
                                                                                                                        amount: number,
                                                                                                                          currency: CurrencyCode
                                                                                                                          ) =>
                                                                                                                            toYER(
                                                                                                                                amount,
                                                                                                                                    currency,
                                                                                                                                        project.exchangeRates
                                                                                                                                          );

                                                                                                                                          const rate = (
                                                                                                                                            project: Project,
                                                                                                                                              currency: CurrencyCode
                                                                                                                                              ) =>
                                                                                                                                                rateOf(
                                                                                                                                                    currency,
                                                                                                                                                        project.exchangeRates
                                                                                                                                                          );

                                                                                                                                                          export function addOwnerPayment(
                                                                                                                                                            project: Project,
                                                                                                                                                              data: Base
                                                                                                                                                              ) {
                                                                                                                                                                const amount = data.amount || 0;

                                                                                                                                                                  return commit(project, [
                                                                                                                                                                      makeTx(project, {
                                                                                                                                                                            type: 'owner_payment',
                                                                                                                                                                                  direction: 'income',
                                                                                                                                                                                        title:
                                                                                                                                                                                                data.title ||
                                                                                                                                                                                                        'دفعة من المالك',
                                                                                                                                                                                                              amountYER:
                                                                                                                                                                                                                      amountYER(
                                                                                                                                                                                                                                project,
                                                                                                                                                                                                                                          amount,
                                                                                                                                                                                                                                                    data.currency
                                                                                                                                                                                                                                                            ),
                                                                                                                                                                                                                                                                  originalAmount: amount,
                                                                                                                                                                                                                                                                        currency: data.currency,
                                                                                                                                                                                                                                                                              exchangeRate:
                                                                                                                                                                                                                                                                                      rate(project, data.currency),
                                                                                                                                                                                                                                                                                            date: data.date,
                                                                                                                                                                                                                                                                                                  notes: data.notes,
                                                                                                                                                                                                                                                                                                      }),
                                                                                                                                                                                                                                                                                                        ]);
                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                        export function addOwnerItem(
                                                                                                                                                                                                                                                                                                          project: Project,
                                                                                                                                                                                                                                                                                                            data: Base
                                                                                                                                                                                                                                                                                                            ) {
                                                                                                                                                                                                                                                                                                              const total =
                                                                                                                                                                                                                                                                                                                  (data.quantity || 0) *
                                                                                                                                                                                                                                                                                                                      (data.unitPrice || 0);

                                                                                                                                                                                                                                                                                                                        return commit(project, [
                                                                                                                                                                                                                                                                                                                            makeTx(project, {
                                                                                                                                                                                                                                                                                                                                  type: 'owner_item',
                                                                                                                                                                                                                                                                                                                                        direction: 'income',
                                                                                                                                                                                                                                                                                                                                              title:
                                                                                                                                                                                                                                                                                                                                                      data.title ||
                                                                                                                                                                                                                                                                                                                                                              'بند',
                                                                                                                                                                                                                                                                                                                                                                    quantity: data.quantity,
                                                                                                                                                                                                                                                                                                                                                                          unit: data.unit,
                                                                                                                                                                                                                                                                                                                                                                                unitPrice: data.unitPrice,
                                                                                                                                                                                                                                                                                                                                                                                      unitPriceCurrency: data.currency,
                                                                                                                                                                                                                                                                                                                                                                                            amountYER:
                                                                                                                                                                                                                                                                                                                                                                                                    amountYER(
                                                                                                                                                                                                                                                                                                                                                                                                              project,
                                                                                                                                                                                                                                                                                                                                                                                                                        total,
                                                                                                                                                                                                                                                                                                                                                                                                                                  data.currency
                                                                                                                                                                                                                                                                                                                                                                                                                                          ),
                                                                                                                                                                                                                                                                                                                                                                                                                                                originalAmount: total,
                                                                                                                                                                                                                                                                                                                                                                                                                                                      currency: data.currency,
                                                                                                                                                                                                                                                                                                                                                                                                                                                            exchangeRate:
                                                                                                                                                                                                                                                                                                                                                                                                                                                                    rate(project, data.currency),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                          date: data.date,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                notes: data.notes,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }),
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      ]);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }

